def average_score(user):
    if user is None:
        return 0.0
    if not hasattr(user, 'total_score') or not hasattr(user, 'num_scores'):
        return 0.0
    total_score = user.total_score
    num_scores = user.num_scores
    if num_scores == 0:
        return 0.0
    return total_score / num_scores

def process_list(input_list):
    if not input_list:
        return []
    results = []
    for sublist in input_list:
        if not sublist:
            continue
        if len(sublist) < 2:
            continue
        try:
            results.append(sublist[0] / sublist[1])
        except ZeroDivisionError:
            results.append(0)
    return results

def process_data(data=None):
    if data is None:
        data = []
    if not isinstance(data, list):
        raise TypeError("Input data must be a list")
    result = []
    for item in data:
        if item is not None and hasattr(item, 'value'):
            result.append(item.value)
    return result
